INSERT INTO `animes` (`id`, `title`, `image_url`, `score`, `rank`, `popularity`, `format`, `episodes`, `status`, `season`, `genres`, `user_rating`, `created_at`, `updated_at`, `global_score`, `description`, `mal_id`, `progress`, `is_completed_season`, `completed_seasons`, `group_name`, `sort_order`) VALUES
(49, 'Shingeki no Kyojin', 'https://myanimelist.net/images/anime/10/47347l.jpg', '9.0', 121, 1, 'TV', 25, 'Completed', 'Spring 2013', '[\"Action\", \"Award Winning\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:02:46', '2026-03-11 16:56:50', '8.6', 'Centuries ago, mankind was slaughtered to near extinction by monstrous humanoid creatures called Titans, forcing humans to hide in fear behind enormous concentric walls. What makes these giants truly terrifying is that their taste for human flesh is not born out of hunger but what appears to be out of pleasure. To ensure their survival, the remnants of humanity began living within defensive barriers, resulting in one hundred years without a single titan encounter. However, that fragile calm is soon shattered when a colossal Titan manages to breach the supposedly impregnable outer wall, reigniting the fight for survival against the man-eating abominations.\r\n\r\nAfter witnessing a horrific personal loss at the hands of the invading creatures, Eren Yeager dedicates his life to their eradication by enlisting into the Survey Corps, an elite military unit that combats the merciless humanoids outside the protection of the walls. Eren, his adopted sister Mikasa Ackerman, and his childhood friend Armin Arlert join the brutal war against the Titans and race to discover a way of defeating them before the last walls are breached.\r\n\r\n[Written by MAL Rewrite]', 16498, 25, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 2);
INSERT INTO `animes` (`id`, `title`, `image_url`, `score`, `rank`, `popularity`, `format`, `episodes`, `status`, `season`, `genres`, `user_rating`, `created_at`, `updated_at`, `global_score`, `description`, `mal_id`, `progress`, `is_completed_season`, `completed_seasons`, `group_name`, `sort_order`) VALUES
(50, 'Shingeki no Kyojin Season 2', 'https://myanimelist.net/images/anime/4/84177l.jpg', '8.5', 142, 12, 'TV', 12, 'Completed', 'Spring 2017', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:03:47', '2026-03-11 16:56:50', '8.5', 'For centuries, humanity has been hunted by giant, mysterious predators known as the Titans. Three mighty walls—Wall Maria, Rose, and Sheena—provided peace and protection for humanity for over a hundred years. That peace, however, was shattered when the Colossal Titan and Armored Titan appeared and destroyed the outermost wall, Wall Maria. Forced to retreat behind Wall Rose, humanity waited with bated breath for the Titans to reappear and destroy their safe haven once more.\r\n\r\nIn Shingeki no Kyojin Season 2, Eren Yeager and others of the 104th Training Corps have just begun to become full members of the Survey Corps. As they ready themselves to face the Titans once again, their preparations are interrupted by the invasion of Wall Rose—but all is not as it seems as more mysteries are unraveled. As the Survey Corps races to save the wall, they uncover more about the invading Titans and the dark secrets of their own members.\r\n\r\n[Written by MAL Rewrite]', 25777, 12, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 3),
(51, 'Shingeki no Kyojin Season 3', 'https://myanimelist.net/images/anime/1173/92110l.jpg', '9.0', 86, 18, 'TV', 12, 'Completed', 'Summer 2018', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:04:35', '2026-03-11 16:56:50', '8.6', 'Still threatened by the \"Titans\" that rob them of their freedom, mankind remains caged inside the two remaining walls. Efforts to eradicate these monsters continue; however, threats arise not only from the Titans beyond the walls, but from the humans within them as well.\r\n\r\nAfter being rescued from the Colossal and Armored Titans, Eren Yaeger devotes himself to improving his Titan form. Krista Lenz struggles to accept the loss of her friend, Captain Levi chooses Eren and his friends to form his new personal squad, and Commander Erwin Smith recovers from his injuries. All seems well for the soldiers, until the government suddenly demands custody of Eren and Krista. The Survey Corps\' recent successes have drawn attention, and a familiar face from Levi\'s past is sent to collect the wanted soldiers. Sought after by the government, Levi and his new squad must evade their adversaries in hopes of keeping Eren and Krista safe.\r\n\r\nEren and his fellow soldiers are not only fighting for their survival against the terrifying Titans, but also against the terror of a far more conniving foe: their fellow humans.\r\n\r\n[Written by MAL Rewrite]', 35760, 12, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 1),
(52, 'Shingeki no Kyojin Season 3 Part 2', 'https://myanimelist.net/images/anime/1517/100633l.jpg', '9.0', 6, 20, 'TV', 10, 'Completed', 'Spring 2019', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:05:00', '2026-03-06 18:05:00', '9.1', 'Seeking to restore humanity\'s diminishing hope, the Survey Corps embark on a mission to retake Wall Maria, where the battle against the merciless \"Titans\" takes the stage once again.\r\n\r\nReturning to the tattered Shiganshina District that was once his home, Eren Yeager and the Corps find the town oddly unoccupied by Titans. Even after the outer gate is plugged, they strangely encounter no opposition. The mission progresses smoothly until Armin Arlert, highly suspicious of the enemy\'s absence, discovers distressing signs of a potential scheme against them. \r\n\r\nShingeki no Kyojin Season 3 Part 2 follows Eren as he vows to take back everything that was once his. Alongside him, the Survey Corps strive—through countless sacrifices—to carve a path towards victory and uncover the secrets locked away in the Yeager family\'s basement.\r\n\r\n[Written by MAL Rewrite]', 38524, 10, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 0),
(53, 'Shingeki no Kyojin Season 3 Part 2', 'https://myanimelist.net/images/anime/1517/100633l.jpg', '9.0', 6, 20, 'TV', 10, 'Completed', 'Spring 2019', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:05:31', '2026-03-06 18:05:31', '9.1', 'Seeking to restore humanity\'s diminishing hope, the Survey Corps embark on a mission to retake Wall Maria, where the battle against the merciless \"Titans\" takes the stage once again.\r\n\r\nReturning to the tattered Shiganshina District that was once his home, Eren Yeager and the Corps find the town oddly unoccupied by Titans. Even after the outer gate is plugged, they strangely encounter no opposition. The mission progresses smoothly until Armin Arlert, highly suspicious of the enemy\'s absence, discovers distressing signs of a potential scheme against them. \r\n\r\nShingeki no Kyojin Season 3 Part 2 follows Eren as he vows to take back everything that was once his. Alongside him, the Survey Corps strive—through countless sacrifices—to carve a path towards victory and uncover the secrets locked away in the Yeager family\'s basement.\r\n\r\n[Written by MAL Rewrite]', 38524, 10, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 0),
(54, 'Shingeki no Kyojin: The Final Season', 'https://myanimelist.net/images/anime/1000/110531l.jpg', '9.0', 38, 30, 'TV', 16, 'Completed', 'Winter 2021', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:06:05', '2026-03-06 18:06:05', '8.8', 'Gabi Braun and Falco Grice have been training their entire lives to inherit one of the seven Titans under Marley\'s control and aid their nation in eradicating the Eldians on Paradis. However, just as all seems well for the two cadets, their peace is suddenly shaken by the arrival of Eren Yeager and the remaining members of the Survey Corps.\r\n\r\nHaving finally reached the Yeager family basement and learned about the dark history surrounding the Titans, the Survey Corps has at long last found the answer they so desperately fought to uncover. With the truth now in their hands, the group set out for the world beyond the walls.\r\n\r\nIn Shingeki no Kyojin: The Final Season, two utterly different worlds collide as each party pursues its own agenda in the long-awaited conclusion to Paradis\' fight for freedom.\r\n\r\n[Written by MAL Rewrite]', 40028, 16, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 0),
(55, 'Shingeki no Kyojin: The Final Season Part 2', 'https://myanimelist.net/images/anime/1948/120625l.jpg', '9.0', 44, 92, 'TV', 12, 'Completed', 'Winter 2022', '[\"Action\", \"Drama\", \"Suspense\"]', 0, '2026-03-06 18:06:20', '2026-03-06 18:06:20', '8.8', 'Turning against his former allies and enemies alike, Eren Yeager sets a disastrous plan in motion. Under the guidance of the Beast Titan, Zeke, Eren takes extreme measures to end the ancient conflict between Marley and Eldia—but his true intentions remain a mystery. Delving deep into his family\'s past, Eren fights to control his own destiny.\r\n\r\nMeanwhile, the long-feuding nations of Marley and Eldia utilize both soldiers and Titans in a brutal race to eliminate the other. Reiner Braun uses his own powers in a desperate bid to hold off Eren\'s own militaristic force, and his fellow Eldians—children Falco Grice and Gabi Braun—struggle to survive in the unfolding chaos.\r\n\r\nElsewhere, Eren\'s childhood friends Mikasa Ackerman and Armin Arlert remain imprisoned alongside Eren\'s former Survey Corps companions, all disturbed by Eren\'s monstrous transformation. Under the blind belief that Eren still secretly harbors good intentions, Mikasa and the others enter the fray in an attempt to save their friend\'s very soul.\r\n\r\n[Written by MAL Rewrite]', 48583, 12, 0, NULL, 'Shingeki no Kyojin (Attack On Titan)', 0),
(56, 'Re:Zero kara Hajimeru Isekai Seikatsu', 'https://myanimelist.net/images/anime/1522/128039l.jpg', '8.5', 371, 23, 'TV', 25, 'Completed', 'Spring 2016', '[\"Drama\", \"Fantasy\", \"Suspense\"]', 0, '2026-03-06 18:07:32', '2026-03-06 18:07:32', '8.2', 'When Subaru Natsuki leaves the convenience store, the last thing he expects is to be wrenched from his everyday life and dropped into a fantasy world. Things are not looking good for the bewildered teenager; however, not long after his arrival, he is attacked by some thugs. Armed with only a bag of groceries and a now useless cell phone, he is quickly beaten to a pulp. Fortunately, a mysterious beauty named Satella, in hot pursuit after the one who stole her insignia, happens upon Subaru and saves him. In order to thank the honest and kindhearted girl, Subaru offers to help in her search, and later that night, he even finds the whereabouts of that which she seeks. But unbeknownst to them, a much darker force stalks the pair from the shadows, and just minutes after locating the insignia, Subaru and Satella are brutally murdered.\r\n\r\nHowever, Subaru immediately reawakens to a familiar scene—confronted by the same group of thugs, meeting Satella all over again—the enigma deepens as history inexplicably repeats itself.\r\n\r\n[Written by MAL Rewrite]', 31240, 25, 0, NULL, 'ReZero', 0),
(58, 'Re:Zero kara Hajimeru Isekai Seikatsu 3rd Season', 'https://myanimelist.net/images/anime/1706/144725l.jpg', NULL, 196, 536, 'TV', 16, 'Plan to watch', 'Fall 2024', '[\"Drama\", \"Fantasy\", \"Suspense\"]', 0, '2026-03-06 18:09:44', '2026-03-11 16:59:53', '8.4', 'One year after the events at the Sanctuary, Subaru Natsuki trains hard to better face future challenges. The peaceful days come to an end when Emilia receives an invitation to a meeting in the Watergate City of Priestella from none other than Anastasia Hoshin, one of her rivals in the royal selection. Considering the meeting\'s significance and the potential dangers Emilia could face, Subaru and his friends accompany her.\r\n\r\nHowever, as Subaru reconnects with old associates and companions in Priestella, new formidable foes emerge. Driven by fanatical motivations and engaging in ruthless methods to achieve their ambitions, the new enemy targets Emilia and threaten the very existence of the city. Rallying his allies, Subaru must give his all once more to stop their nefarious goals from becoming a concrete reality.\r\n\r\n[Written by MAL Rewrite]', 54857, 0, 0, NULL, 'ReZero', 17),
(59, 'Dragon Ball', 'https://myanimelist.net/images/anime/1887/92364l.jpg', '8.5', 747, 150, 'TV', 153, 'Completed', 'Winter 1986', '[\"Action\", \"Adventure\", \"Comedy\", \"Fantasy\"]', 0, '2026-03-06 18:12:02', '2026-03-06 18:12:02', '8.0', 'Gokuu Son is a young boy who lives in the woods all alone—that is, until a girl named Bulma runs into him in her search for a set of magical objects called the \"Dragon Balls.\" Since the artifacts are said to grant one wish to whoever collects all seven, Bulma hopes to gather them and wish for a perfect boyfriend. Gokuu happens to be in possession of a dragon ball, but unfortunately for Bulma, he refuses to part ways with it, so she makes him a deal: he can tag along on her journey if he lets her borrow the dragon ball\'s power. With that, the two set off on the journey of a lifetime.\r\n\r\nThey don\'t go on the journey alone. On the way, they meet the old Muten-Roshi and wannabe disciple Kuririn, with whom Gokuu trains to become a stronger martial artist for the upcoming World Martial Arts Tournament. However, it\'s not all fun and games; the ability to make any wish come true is a powerful one, and there are others who would do much worse than just wishing for a boyfriend. To stop those who would try to abuse the legendary power, they train to become stronger fighters, using their newfound strength to help the people around them along the way.\r\n\r\n[Written by MAL Rewrite]', 223, 153, 0, NULL, 'Dragon Ball', 0),
(60, 'Dragon Ball Super', 'https://myanimelist.net/images/anime/7/74606l.jpg', '8.0', 2222, 222, 'TV', 131, 'Completed', 'Summer 2015', '[\"Action\", \"Adventure\", \"Comedy\", \"Fantasy\"]', 0, '2026-03-06 18:15:36', '2026-03-06 18:15:36', '7.5', 'Seven years after the defeat of Majin Buu, Earth is at peace, and its people live free from any dangers lurking in the universe. However, this peace is short-lived; a sleeping threat awakens in the dark reaches of the galaxy: Beerus, the ruthless God of Destruction.\r\n\r\nDisturbed by a prophecy that he will be defeated by a \"Super Saiyan God,\" Beerus and his angelic attendant Whis search the universe for this mysterious being. Before long, they reach Earth and encounter Gokuu Son, one of the planet\'s mightiest warriors, and his powerful friends.\r\n\r\n[Written by MAL Rewrite]', 30694, 131, 0, NULL, 'Dragon Ball', 0),
(62, 'Re:Zero kara Hajimeru Isekai Seikatsu 2nd Season', 'https://myanimelist.net/images/anime/1444/108005l.jpg', '9.5', 293, 128, 'TV', 13, 'Completed', 'Summer 2020', '[\"Drama\", \"Fantasy\", \"Suspense\"]', 0, '2026-03-06 18:20:59', '2026-03-06 18:20:59', '8.3', 'A reunion that was supposed to spell the arrival of peaceful times is quickly shattered when Subaru Natsuki and Emilia return to Irlam village. Witnessing the devastation left behind by the calamities known as Sin Archbishops, Subaru sinks into the depths of despair as his ability to redo proves futile.\r\n\r\nAs the group makes their way to the Sanctuary in search of answers, Subaru has an unexpected encounter with the Witch of Greed—Echidna. Subjected to her untamed rhythm, he is forced to dive into the spirals of the past and future. At the same time, several mysterious threats set their sights on the Sanctuary, heralding a horrific fate for the hapless people trapped within.\r\n\r\nEverlasting contracts, past sins, and unrequited love will clash and submerge into a river of blood in the second season of Re:Zero kara Hajimeru Isekai Seikatsu. Pushed to the brink of hopelessness, how long will Subaru\'s resolve to save his loved ones last?\r\n\r\n[Written by MAL Rewrite]', 39587, 13, 0, NULL, 'ReZero', 0),
(63, 'Re:Zero kara Hajimeru Isekai Seikatsu 2nd Season Part 2', 'https://myanimelist.net/images/anime/1724/117421l.jpg', '10.0', 212, 173, 'TV', 12, 'Completed', 'Winter 2021', '[\"Drama\", \"Fantasy\", \"Suspense\"]', 0, '2026-03-06 18:21:33', '2026-03-07 06:13:01', '8.4', 'After a stern yet compelling speech by Otto Suwen, Subaru Natsuki solemnly swears that he will successfully make it through this timeline and save everyone he can along the way. The first step toward achieving this goal is to help Emilia work through her past; however, that is easier said than done. Feeling as if she has been lied to by everyone around her, it will be difficult for Emilia to trust anyone, even Subaru, her self-proclaimed knight.\r\n\r\nRe:Zero kara Hajimeru Isekai Seikatsu 2nd Season Part 2 presents the culmination of Subaru\'s experiences with the Sanctuary and its people, along with his unwillingness to give up hope on saving them.\r\n\r\n[Written by MAL Rewrite]', 42203, 12, 0, NULL, 'ReZero', 0),
(64, 'Dragon Ball Kai', 'https://myanimelist.net/images/anime/1102/133990l.jpg', '8.0', 1156, 612, 'TV', 97, 'Completed', 'Spring 2009', '[\"Action\", \"Adventure\", \"Comedy\", \"Fantasy\"]', 0, '2026-03-06 18:23:43', '2026-03-06 18:23:43', '7.8', 'Five years after the events of Dragon Ball, martial arts expert Gokuu is now a grown man married to his wife Chi-Chi, with a four-year old son named Gohan. While attending a reunion on Turtle Island with his old friends Master Roshi, Krillin, Bulma and others, the festivities are interrupted when a humanoid alien named Raditz not only reveals the truth behind Gokuu\'s past, but kidnaps Gohan as well.\r\n\r\nWith Raditz displaying power beyond anything Gokuu has seen before, he is forced to team up with his old nemesis, Piccolo, in order to rescue his son. But when Gokuu and Piccolo reveal the secret of the seven mystical wish-granting Dragon Balls to Raditz, he informs the duo that there is more of his race, the Saiyans, and they won’t pass up an opportunity to seize the power of the Dragon Balls for themselves.\r\n\r\nThese events begin the saga of Dragon Ball Kai, a story that finds Gokuu and his friends and family constantly defending the galaxy from increasingly more powerful threats. Bizarre, comical, heartwarming and threatening characters come together in a series of battles that push the powers and abilities of Gokuu and his friends beyond anything they have ever experienced.', 6033, 97, 0, NULL, 'Dragon Ball', 0),
(65, 'Naruto', 'https://myanimelist.net/images/anime/1141/142503l.jpg', '9.0', 689, 9, 'TV', 220, 'Completed', 'Fall 2002', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:24:41', '2026-03-06 18:24:41', '8.0', 'Twelve years ago, a colossal demon fox terrorized the world. During the monster\'s attack on the Hidden Leaf Village, the Hokage—the village\'s leader and most powerful ninja—sacrifices himself to seal the beast inside a newborn, relieving civilization from destruction while dooming the baby to a lonely life.\r\n\r\nNow, after years of being shunned and bullied, Naruto Uzumaki pesters the village with elaborate pranks and vandalism. Despite these antics, he works hard to achieve his dream: to become the Hokage and earn the acknowledgement of those who have mistreated him for his entire life. Naruto joins Team 7, a ninja squad made up of two of his peers—prodigy Sasuke Uchiha and clever Sakura Haruno.\r\n\r\nUnder the aloof Kakashi Hatake\'s leadership, Team 7 takes on a series of difficult missions, forcing its members to grow in strength and comradery despite their many differences. Naruto strives to stand out in his rivalry with Sasuke and earn the romantic affection of Sakura. But as the trio brush against danger and death, their tragic pasts threaten to tear them apart.\r\n\r\n[Written by MAL Rewrite]', 20, 220, 0, NULL, 'Naruto', 0),
(66, 'Naruto: Shippuuden', 'https://myanimelist.net/images/anime/1565/111305l.jpg', '9.0', 321, 15, 'TV', 500, 'Completed', 'Winter 2007', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:25:51', '2026-03-06 18:25:51', '8.3', 'It has been two and a half years since Naruto Uzumaki left Konohagakure, the Hidden Leaf Village, for intense training following events which fueled his desire to be stronger. Now Akatsuki, the mysterious organization of elite rogue ninja, is closing in on their grand plan which may threaten the safety of the entire shinobi world.\r\n \r\nAlthough Naruto is older and sinister events loom on the horizon, he has changed little in personality—still rambunctious and childish—though he is now far more confident and possesses an even greater determination to protect his friends and home. Come whatever may, Naruto will carry on with the fight for what is important to him, even at the expense of his own body, in the continuation of the saga about the boy who wishes to become Hokage.\r\n\r\n[Written by MAL Rewrite]', 1735, 500, 0, NULL, 'Naruto', 0),
(67, 'The Last: Naruto the Movie', 'https://myanimelist.net/images/anime/1491/134498l.jpg', '9.0', 1143, 366, 'Movie', 1, 'Completed', 'Unknown', '[\"Action\", \"Adventure\", \"Fantasy\", \"Romance\"]', 0, '2026-03-06 18:27:02', '2026-03-06 18:27:02', '7.8', 'Two years have passed since the end of the Fourth Great Ninja War. Konohagakure has remained in a state of peace and harmony—until Sixth Hokage Kakashi Hatake notices the moon is dangerously approaching the Earth, posing the threat of planetary ruin.\r\n\r\nAmidst the grave ordeal, Konoha is invaded by a new evil, Toneri Oosutuski, who suddenly abducts Hinata Hyuuga\'s little sister Hanabi. Kakashi dispatches a skilled ninja team comprised of Naruto Uzumaki, Sakura Haruno, Shikamaru Nara, Sai, and Hinata in an effort to rescue Hanabi from the diabolical clutches of Toneri. However, during their mission, the team faces several obstacles that challenge them, foiling their efforts.\r\n\r\nWith her abduction, the relationships the team share with one another are tested, and with the world reaching the brink of destruction, they must race against time to ensure the safety of their planet. Meanwhile, as the battle ensues, Naruto is driven to fight for something greater than he has ever imagined—love.\r\n\r\n[Written by MAL Rewrite]', 16870, 1, 0, NULL, 'Naruto', 0),
(69, 'Boruto: Naruto Next Generations', 'https://myanimelist.net/images/anime/1091/99847l.jpg', '3.0', 10584, 216, 'TV', 293, 'Dropped', 'Spring 2017', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:31:34', '2026-03-06 18:31:34', '6.0', 'Following the successful end of the Fourth Shinobi World War, Konohagakure has been enjoying a period of peace, prosperity, and extraordinary technological advancement. This is all due to the efforts of the Allied Shinobi Forces and the village\'s Seventh Hokage, Naruto Uzumaki. Now resembling a modern metropolis, Konohagakure has changed, particularly the life of a shinobi. Under the watchful eye of Naruto and his old comrades, a new generation of shinobi has stepped up to learn the ways of the ninja.\r\n\r\nBoruto Uzumaki is often the center of attention as the son of the Seventh Hokage. Despite having inherited Naruto\'s boisterous and stubborn demeanor, Boruto is considered a prodigy and is able to unleash his potential with the help of supportive friends and family. Unfortunately, this has only worsened his arrogance and his desire to surpass Naruto which, along with his father\'s busy lifestyle, has strained their relationship. However, a sinister force brewing within the village may threaten Boruto\'s carefree life.\r\n\r\nNew friends and familiar faces join Boruto as a new story begins.\r\n\r\n[Written by MAL Rewrite]', 34566, 150, 0, NULL, 'Boruto', 0),
(70, 'Boku no Hero Academia', 'https://myanimelist.net/images/anime/10/78745l.jpg', '8.0', 1042, 7, 'TV', 13, 'Completed', 'Spring 2016', '[\"Action\"]', 0, '2026-03-06 18:32:54', '2026-03-06 18:32:54', '7.8', 'The appearance of \"quirks,\" newly discovered super powers, has been steadily increasing over the years, with 80 percent of humanity possessing various abilities from manipulation of elements to shapeshifting. This leaves the remainder of the world completely powerless, and Izuku Midoriya is one such individual.\r\n\r\nSince he was a child, the ambitious middle schooler has wanted nothing more than to be a hero. Izuku\'s unfair fate leaves him admiring heroes and taking notes on them whenever he can. But it seems that his persistence has borne some fruit: Izuku meets the number one hero and his personal idol, All Might. All Might\'s quirk is a unique ability that can be inherited, and he has chosen Izuku to be his successor!\r\n\r\nEnduring many months of grueling training, Izuku enrolls in UA High, a prestigious high school famous for its excellent hero training program, and this year\'s freshmen look especially promising. With his bizarre but talented classmates and the looming threat of a villainous organization, Izuku will soon learn what it really means to be a hero.\r\n\r\n[Written by MAL Rewrite]', 31964, 13, 0, NULL, 'Boku no Hero Academia', 0),
(71, 'Boku no Hero Academia 2nd Season', 'https://myanimelist.net/images/anime/12/85221l.jpg', '8.0', 636, 16, 'TV', 25, 'Completed', 'Spring 2017', '[\"Action\"]', 0, '2026-03-06 18:33:08', '2026-03-06 18:33:08', '8.1', 'At UA Academy, not even a violent attack can disrupt their most prestigious event: the school sports festival. Renowned across Japan, this festival is an opportunity for aspiring heroes to showcase their abilities, both to the public and potential recruiters.\r\n\r\nHowever, the path to glory is never easy, especially for Izuku Midoriya—whose quirk possesses great raw power but is also cripplingly inefficient. Pitted against his talented classmates, such as the fire and ice wielding Shouto Todoroki, Izuku must utilize his sharp wits and master his surroundings to achieve victory and prove to the world his worth.\r\n\r\n[Written by MAL Rewrite]', 33486, 25, 0, NULL, 'Boku no Hero Academia', 0),
(72, 'Boku no Hero Academia 3rd Season', 'https://myanimelist.net/images/anime/1319/92084l.jpg', '8.0', 745, 25, 'TV', 25, 'Completed', 'Spring 2018', '[\"Action\"]', 0, '2026-03-06 18:33:41', '2026-03-06 18:33:41', '8.0', 'As summer arrives for the students at UA Academy, each of these superheroes-in-training puts in their best efforts to become renowned heroes. They head off to a forest training camp run by UA\'s pro heroes, where the students face one another in battle and go through dangerous tests, improving their abilities and pushing past their limits. However, their school trip is suddenly turned upside down when the League of Villains arrives, invading the camp with a mission to capture one of the students. \r\n\r\nBoku no Hero Academia 3rd Season follows Izuku \"Deku\" Midoriya, an ambitious student training to achieve his dream of becoming a hero similar to his role model—All Might. Being one of the students caught up amidst the chaos of the villain attack, Deku must take a stand with his classmates and fight for their survival.\r\n\r\n[Written by MAL Rewrite]', 36456, 25, 0, NULL, 'Boku no Hero Academia', 0),
(73, 'Boku dake ga Inai Machi', 'https://myanimelist.net/images/anime/10/77957l.jpg', '8.5', 310, 29, 'TV', 12, 'Completed', 'Winter 2016', '[\"Mystery\", \"Suspense\"]', 0, '2026-03-06 18:35:03', '2026-03-11 17:02:51', '8.3', 'When tragedy is about to strike, Satoru Fujinuma finds himself sent back several minutes before the accident occurs. The detached, 29-year-old manga artist has taken advantage of this powerful yet mysterious phenomenon, which he calls \"Revival,\" to save many lives.\r\n \r\nHowever, when he is wrongfully accused of murdering someone close to him, Satoru is sent back to the past once again, but this time to 1988, 18 years in the past. Soon, he realizes that the murder may be connected to the abduction and killing of one of his classmates, the solitary and mysterious Kayo Hinazuki, that took place when he was a child. This is his chance to make things right.\r\n \r\nBoku dake ga Inai Machi follows Satoru in his mission to uncover what truly transpired 18 years ago and prevent the death of his classmate while protecting those he cares about in the present.\r\n\r\n[Written by MAL Rewrite]', 31043, 12, 0, NULL, 'Erased', 7),
(74, 'Black Clover', 'https://myanimelist.net/images/anime/2/88336l.jpg', '8.6', 503, 55, 'TV', 170, 'Completed', 'Fall 2017', '[\"Action\", \"Fantasy\"]', 0, '2026-03-06 18:35:59', '2026-03-11 17:02:51', '8.1', 'Asta and Yuno were abandoned at the same church on the same day. Raised together as children, they came to know of the \"Wizard King\"—a title given to the strongest mage in the kingdom—and promised that they would compete against each other for the position of the next Wizard King. However, as they grew up, the stark difference between them became evident. While Yuno is able to wield magic with amazing power and control, Asta cannot use magic at all and desperately tries to awaken his powers by training physically.\r\n\r\nWhen they reach the age of 15, Yuno is bestowed a spectacular Grimoire with a four-leaf clover, while Asta receives nothing. However, soon after, Yuno is attacked by a person named Lebuty, whose main purpose is to obtain Yuno\'s Grimoire. Asta tries to fight Lebuty, but he is outmatched. Though without hope and on the brink of defeat, he finds the strength to continue when he hears Yuno\'s voice. Unleashing his inner emotions in a rage, Asta receives a five-leaf clover Grimoire, a \"Black Clover\" giving him enough power to defeat Lebuty. A few days later, the two friends head out into the world, both seeking the same goal—to become the Wizard King!\r\n\r\n[Written by MAL Rewrite]', 34572, 170, 0, NULL, 'Black Clover', 6),
(75, 'Blue Eye Samurai', NULL, '9.0', NULL, NULL, 'TV Series', 8, 'Completed', NULL, '[\"Action\", \"Adventure\"]', 0, '2026-03-06 18:43:02', '2026-03-11 17:02:50', '8.7', NULL, NULL, 8, 0, NULL, 'Blue Eye Samurai', 5),
(76, 'Dororo', 'https://myanimelist.net/images/anime/1879/100467l.jpg', '9.0', 357, 107, 'TV', 24, 'Completed', 'Winter 2019', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:44:17', '2026-03-11 17:02:50', '8.3', 'The greedy samurai lord Daigo Kagemitsu\'s land is dying, and he would do anything for power, even renounce Buddha and make a pact with demons. His prayers are answered by 12 demons who grant him the power he desires by aiding his prefecture\'s growth, but at a price. When Kagemitsu\'s first son is born, the boy has no limbs, no nose, no eyes, no ears, nor even skin—yet still, he lives.\r\n\r\nThis child is disposed of in a river and forgotten. But as luck would have it, he is saved by a medicine man who provides him with prosthetics and weapons, allowing for him to survive and fend for himself. The boy lives and grows, and although he cannot see, hear, or feel anything, he must defeat the demons that took him as sacrifice. With the death of each one, he regains a part of himself that is rightfully his. For many years he wanders alone, until one day an orphan boy, Dororo, befriends him. The unlikely pair of castaways now fight for their survival and humanity in an unforgiving, demon-infested world.\r\n\r\n[Written by MAL Rewrite]', 37520, 24, 0, NULL, 'Dororo', 4),
(77, 'Hai to Gensou no Grimgar', 'https://myanimelist.net/images/anime/13/77976l.jpg', '8.0', 1487, 281, 'TV', 12, 'Completed', 'Winter 2016', '[\"Action\", \"Adventure\", \"Drama\", \"Fantasy\"]', 0, '2026-03-06 18:46:52', '2026-03-11 17:02:50', '7.7', 'Fear, survival, instinct. Thrown into a foreign land with nothing but hazy memories and the knowledge of their name, they can feel only these three emotions resonating deep within their souls. A group of strangers is given no other choice than to accept the only paying job in this game-like world—the role of a soldier in the Reserve Army—and eliminate anything that threatens the peace in their new world, Grimgar.\r\n\r\nWhen all of the stronger candidates join together, those left behind must create a party together to survive: Manato, a charismatic leader and priest; Haruhiro, a nervous thief; Yume, a cheerful hunter; Shihoru, a shy mage; Moguzo, a kind warrior; and Ranta, a rowdy dark knight. Despite its resemblance to one, this is no game—there are no redos or respawns; it is kill or be killed. \r\n\r\nIt is now up to this ragtag group of unlikely fighters to survive together in a world where life and death are separated only by a fine line. \r\n\r\n[Written by MAL Rewrite]', 31859, 12, 0, NULL, 'Hai to Gensou no Grimgar', 3),
(78, 'Kenpuu Denki Berserk', 'https://myanimelist.net/images/anime/1384/119988l.jpg', '9.0', 100, 301, 'TV', 25, 'Completed', 'Fall 1997', '[\"Action\", \"Adventure\", \"Drama\", \"Fantasy\", \"Horror\"]', 0, '2026-03-06 18:50:11', '2026-03-11 17:02:50', '8.6', 'Guts, a man who will one day be known as the Black Swordsman, is a young traveling mercenary characterized by the large greatsword he carries. He accepts jobs that offer the most money, but he never stays with one group for long—until he encounters the Band of the Falcon. Ambushed after completing a job, Guts crushes many of its members in combat. Griffith, The Band of the Falcon\'s leader and founder, takes an interest in Guts and duels him. While the others are no match for Guts, Griffith defeats him in one blow.\r\n\r\nIncapacitated and taken into the Band of the Falcon\'s camp to recover, Guts wakes up two days later. He confronts Griffith, and the two duel yet again, only this time with a condition: Guts will join the Band of the Falcon if he loses. Due to his fresh injuries, Guts loses the fight and is inducted by Griffith.\r\n\r\nIn three years\' time, Guts has become one of the Band of the Falcon\'s commanders. On the battlefield, his combat prowess is second only to Griffith as he takes on large groups of enemies all on his own. With Guts\' immense strength and Griffith\'s leadership, the Band of the Falcon dominate every battle they partake in. But something menacing lurks in the shadows, threatening to change Guts\' life forever.\r\n\r\n[Written by MAL Rewrite]', 33, 25, 0, NULL, 'Berserk', 2),
(79, 'Tokyo Ghoul', 'https://myanimelist.net/images/anime/1498/134443l.jpg', '9.0', 1144, 10, 'TV', 12, 'Completed', 'Summer 2014', '[\"Action\", \"Fantasy\", \"Horror\", \"Suspense\"]', 0, '2026-03-06 18:51:40', '2026-03-06 18:51:40', '7.8', 'A sinister threat is invading Tokyo: flesh-eating \"ghouls\" who appear identical to humans and blend into their population. Reserved college student Ken Kaneki buries his nose in books and avoids the news of the growing crisis. However, the appearance of an attractive woman named Rize Kamishiro shatters his solitude when she forwardly asks him on a date.\r\n\r\nWhile walking Rize home, Kaneki discovers she isn\'t as kind as she first appeared, and she has led him on with sinister intent. After a tragic struggle, he later awakens in a hospital to learn his life was saved by transplanting the now deceased Rize\'s organs into his own body.\r\n\r\nKaneki\'s body begins to change in horrifying ways, and he transforms into a human-ghoul hybrid. As he embarks on his new dreadful journey, Kaneki clings to his humanity in the evolving bloody conflict between society\'s new monsters and the government agents who hunt them.\r\n\r\n[Written by MAL Rewrite]', 22319, 12, 0, NULL, 'Tokyo Ghoul', 0),
(80, 'Tokyo Ghoul √A', 'https://myanimelist.net/images/anime/1889/123307l.jpg', '9.0', 4511, 54, 'TV', 12, 'Completed', 'Winter 2015', '[\"Action\", \"Fantasy\", \"Horror\", \"Suspense\"]', 0, '2026-03-06 18:52:23', '2026-03-06 18:52:23', '7.0', 'Ken Kaneki has finally come to accept the monstrous, flesh-craving part of himself that he has feared and despised for so long. After escaping captivity and torture, Kaneki joins Aogiri Tree—the very militant ghoul organization that had abducted him, leading his friends to question his true motive and loyalty.\r\n\r\nAs tension between the government and the ghouls continues to rise, the Commission of Counter Ghoul, the government\'s specialized anti-ghoul agency, has intensified their efforts to completely purge Tokyo of ghouls. This threatens the transient peace of Kaneki\'s friends and former comrades—the ghouls at the Anteiku coffee shop. Aware of the dangerous situation, Kaneki faces several battles that puts his precious fleeting humanity on the line.\r\n\r\n[Written by MAL Rewrite]', 27899, 12, 0, NULL, 'Tokyo Ghoul', 0),
(81, 'Tokyo Ghoul:re', 'https://myanimelist.net/images/anime/1063/95086l.jpg', '7.0', 8339, 122, 'TV', 12, 'Completed', 'Spring 2018', '[\"Action\", \"Fantasy\", \"Horror\", \"Suspense\"]', 0, '2026-03-06 18:53:01', '2026-03-06 18:53:01', '6.4', 'Two years have passed since the CCG\'s raid on Anteiku. Although the atmosphere in Tokyo has changed drastically due to the increased influence of the CCG, ghouls continue to pose a problem as they have begun taking caution, especially the terrorist organization Aogiri Tree, who acknowledge the CCG\'s growing threat to their existence.\r\n\r\nThe creation of a special team, known as the Quinx Squad, may provide the CCG with the push they need to exterminate Tokyo\'s unwanted residents. As humans who have undergone surgery in order to make use of the special abilities of ghouls, they participate in operations to eradicate the dangerous creatures. The leader of this group, Haise Sasaki, is a half-ghoul, half-human who has been trained by famed special class investigator, Kishou Arima. However, there\'s more to this young man than meets the eye, as unknown memories claw at his mind, slowly reminding him of the person he used to be.\r\n\r\n[Written by MAL Rewrite]', 36511, 12, 0, NULL, 'Tokyo Ghoul', 0),
(82, 'Fate/Zero', 'https://myanimelist.net/images/anime/1887/117644l.jpg', '8.0', 359, 83, 'TV', 13, 'Completed', 'Fall 2011', '[\"Action\", \"Fantasy\"]', 0, '2026-03-06 18:54:56', '2026-03-06 18:54:56', '8.3', 'With the promise of granting any wish, the omnipotent Holy Grail triggered three wars in the past, each too cruel and fierce to leave a victor. In spite of that, the wealthy Einzbern family is confident that the Fourth Holy Grail War will be different; namely, with a vessel of the Holy Grail now in their grasp. Solely for this reason, the much hated \"Magus Killer\" Kiritsugu Emiya is hired by the Einzberns, with marriage to their only daughter Irisviel as binding contract.\r\n\r\nKiritsugu now stands at the center of a cutthroat game of survival, facing off against six other participants, each armed with an ancient familiar, and fueled by unique desires and ideals. Accompanied by his own familiar, Saber, the notorious mercenary soon finds his greatest opponent in Kirei Kotomine, a priest who seeks salvation from the emptiness within himself in pursuit of Kiritsugu.\r\n\r\nBased on the light novel written by Gen Urobuchi, Fate/Zero depicts the events of the Fourth Holy Grail War—10 years prior to Fate/stay night. Witness a battle royale in which no one is guaranteed to survive.\r\n\r\n[Written by MAL Rewrite]', 10087, 13, 0, NULL, 'Fate/Zero', 0),
(83, 'Fate/Zero 2nd Season', 'https://myanimelist.net/images/anime/1522/117645l.jpg', '8.0', 140, 140, 'TV', 12, 'Completed', 'Spring 2012', '[\"Action\", \"Fantasy\"]', 0, '2026-03-06 18:55:11', '2026-03-06 18:55:11', '8.5', 'As the Fourth Holy Grail War rages on with no clear victor in sight, the remaining Servants and their Masters are called upon by Church supervisor Risei Kotomine, in order to band together and confront an impending threat that could unravel the Grail War and bring about the destruction of Fuyuki City. The uneasy truce soon collapses as Masters demonstrate that they will do anything in their power, no matter how despicable, to win.\r\n\r\nSeeds of doubt are sown between Kiritsugu Emiya and Saber, his Servant, as their conflicting ideologies on heroism and chivalry clash. Meanwhile, an ominous bond forms between Kirei Kotomine, who still seeks to find his purpose in life, and one of the remaining Servants. As the countdown to the end of the war reaches zero, the cost of winning begins to blur the line between victory and defeat.\r\n\r\n[Written by MAL Rewrite]', 11741, 12, 0, NULL, 'Fate/Zero', 0),
(84, 'Log Horizon', 'https://myanimelist.net/images/anime/5/84004l.jpg', '8.0', 891, 141, 'TV', 25, 'Completed', 'Fall 2013', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:55:45', '2026-03-11 17:02:50', '7.9', 'In the blink of an eye, thirty thousand bewildered Japanese gamers are whisked from their everyday lives into the world of the popular MMORPG, Elder Tale, after the game\'s latest update—unable to log out. Among them is the socially awkward college student Shiroe, whose confusion and shock lasts only a moment as, a veteran of the game, he immediately sets out to explore the limits of his new reality.\r\n\r\nShiroe must learn to live in this new world, leading others and negotiating with the NPC \"natives\" in order to bring stability to the virtual city of Akihabara. He is joined by his unfortunate friend Naotsugu, having logged in for the first time in years only to find himself trapped, and Akatsuki, a petite but fierce assassin who labels Shiroe as her master. A tale of fantasy, adventure, and politics, Log Horizon explores the elements of gaming through the eyes of a master strategist who attempts to make the best of a puzzling situation.\r\n\r\n[Written by MAL Rewrite]', 17265, 25, 0, NULL, 'Log Horizon', 1),
(85, 'Log Horizon 2nd Season', 'https://myanimelist.net/images/anime/5/68097l.jpg', '7.5', 1861, 379, 'TV', 25, 'Dropped', 'Fall 2014', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 18:56:15', '2026-03-06 18:56:15', '7.6', 'After being trapped in the world of Elder Tale for six months, Shiroe and the other Adventurers have begun to get the hang of things in their new environment. The Adventurers are starting to gain the trust of the People of the Land, and Akiba has flourished thanks to the law and order established by Shiroe\'s Round Table Alliance, regaining its everyday liveliness. Despite this success, however, the Alliance faces a new crisis: they are running out of funds to govern Akiba, and spies from the Minami district have infiltrated the city.\r\n\r\nAs formidable forces rise in other districts, there is also a need to discover more about the vast new world they are trapped in—leading Shiroe to decide that the time has come to venture outside the city. Accompanied by his friend Naotsugu and the Sage of Mirror Lake Regan, the calculative Shiroe makes his move, hoping to unravel new possibilities and eventually find a way home.\r\n\r\n[Written by MAL Rewrite]', 23321, 17, 0, NULL, 'Log Horizon', 0),
(86, 'Code Geass: Hangyaku no Lelouch', 'https://myanimelist.net/images/anime/1032/135088l.jpg', '8.5', 58, 22, 'TV', 25, 'Completed', 'Fall 2006', '[\"Award Winning\", \"Drama\", \"Sci-Fi\"]', 0, '2026-03-06 18:57:23', '2026-03-06 18:57:23', '8.7', 'In the year 2010, the Holy Empire of Britannia is establishing itself as a dominant military nation, starting with the conquest of Japan. Renamed to Area 11 after its swift defeat, Japan has seen significant resistance against these tyrants in an attempt to regain independence.\r\n\r\nLelouch Lamperouge, a Britannian student, unfortunately finds himself caught in a crossfire between the Britannian and the Area 11 rebel armed forces. He is able to escape, however, thanks to the timely appearance of a mysterious girl named C.C., who bestows upon him Geass, the \"Power of Kings.\" Realizing the vast potential of his newfound \"power of absolute obedience,\" Lelouch embarks upon a perilous journey as the masked vigilante known as Zero, leading a merciless onslaught against Britannia in order to get revenge once and for all.\r\n\r\n[Written by MAL Rewrite]', 1575, 25, 0, NULL, 'Code Geass', 0),
(87, 'Code Geass: Hangyaku no Lelouch R2', 'https://myanimelist.net/images/anime/1088/135089l.jpg', '8.9', 22, 48, 'TV', 25, 'Completed', 'Spring 2008', '[\"Award Winning\", \"Drama\", \"Sci-Fi\"]', 0, '2026-03-06 18:58:20', '2026-03-06 18:58:20', '8.9', 'One year has passed since the Black Rebellion, a failed uprising against the Holy Britannian Empire led by the masked vigilante Zero, who is now missing. At a loss without their revolutionary leader, Area 11\'s resistance group—the Black Knights—find themselves too powerless to combat the brutality inflicted upon the Elevens by Britannia, which has increased significantly in order to crush any hope of a future revolt. \r\n\r\nLelouch Lamperouge, having lost all memory of his double life, is living peacefully alongside his friends as a high school student at Ashford Academy. His former partner C.C., unable to accept this turn of events, takes it upon herself to remind him of his past purpose, hoping that the mastermind Zero will rise once again to finish what he started.\r\n\r\n[Written by MAL Rewrite]', 2904, 25, 0, NULL, 'Code Geass', 0),
(88, '86', 'https://myanimelist.net/images/anime/1987/117507l.jpg', '8.8', 274, 204, 'TV', 11, 'Completed', 'Spring 2021', '[\"Drama\", \"Sci-Fi\"]', 0, '2026-03-06 18:59:01', '2026-03-06 18:59:01', '8.3', 'According to the Republic of San Magnolia, their ongoing war against the Giadian Empire has no casualties—however, that is mere propaganda. While the silver-haired Alba of the Republic\'s eighty-five sectors live safely behind protective walls, those of different appearances are interned in a secret eighty-sixth faction. Known within the military as the Eighty-Six, they are forced to fight against the Empire\'s autonomous Legion under the command of the Republican \"Handlers.\"\r\n\r\nVladilena Milizé is assigned to the Spearhead squadron to replace their previous Handler. Shunned by her peers for being a fellow Eighty-Six supporter, she continues to fight against their inhumane discrimination. Shinei Nouzen is the captain of the Spearhead squadron. Infamous for being the sole survivor of every squadron he\'s been in, he insists on shouldering the names and wishes of his fallen comrades. When the fates of these young souls from two different worlds collide, will it ignite the spark that lights their path to salvation, or will they burn themselves in the flames of despair?\r\n\r\n[Written by MAL Rewrite]', 41457, 11, 0, NULL, '86', 0),
(89, '86 Part 2', 'https://myanimelist.net/images/anime/1321/117508l.jpg', '9.0', 55, 388, 'TV', 12, 'Completed', 'Fall 2021', '[\"Drama\", \"Sci-Fi\"]', 0, '2026-03-06 18:59:18', '2026-03-06 18:59:18', '8.7', 'The disappearance of the Spearhead Squadron beyond the horizon does little to hide the intensity of the Republic of San Magnolia\'s endless propaganda. Vladilena Milizé continues to operate as \"Handler One,\" the commander of yet another dehumanized 86th faction\'s squadron in the continuous war against the Legion.\r\n\r\nOn the Western Front, Shinei Nouzen and his squad are quarantined in a military base controlled by the Federal Republic of Giad, formerly known as the Giadian Empire. The newly-established government grants the saved Eighty-Six full citizenship and freedom. Housed by the president Ernst Zimmerman himself, the group meets his adoptive daughter and the last Empress, Augusta Frederica Adel-Adler.\r\n\r\nHowever, within the calm of this tender society, Shinei and his team feel that their purpose is on the battlefield. Before long, they are once again in the midst of the Legion\'s onslaught as a part of the Federacy\'s Nordlicht Squadron, accompanied by Augusta Frederica. But, as history repeats itself, they realize that no matter the side, death and pain on the front lines are the only comfort they know.\r\n\r\n[Written by MAL Rewrite]', 48569, 12, 0, NULL, '86', 0),
(90, 'Vinland Saga', 'https://myanimelist.net/images/anime/1500/103005l.jpg', '8.5', 39, 62, 'TV', 24, 'Completed', 'Summer 2019', '[\"Action\", \"Adventure\", \"Drama\"]', 0, '2026-03-06 18:59:50', '2026-03-06 18:59:50', '8.8', 'Young Thorfinn grew up listening to the stories of old sailors that had traveled the ocean and reached the place of legend, Vinland. It\'s said to be warm and fertile, a place where there would be no need for fighting—not at all like the frozen village in Iceland where he was born, and certainly not like his current life as a mercenary. War is his home now. Though his father once told him, \"You have no enemies, nobody does. There is nobody who it\'s okay to hurt,\" as he grew, Thorfinn knew that nothing was further from the truth.\r\n\r\nThe war between England and the Danes grows worse with each passing year. Death has become commonplace, and the viking mercenaries are loving every moment of it. Allying with either side will cause a massive swing in the balance of power, and the vikings are happy to make names for themselves and take any spoils they earn along the way. Among the chaos, Thorfinn must take his revenge and kill Askeladd, the man who murdered his father. The only paradise for the vikings, it seems, is the era of war and death that rages on.\r\n\r\n[Written by MAL Rewrite]', 37521, 24, 0, NULL, 'Vinland Saga', 0),
(91, 'Vinland Saga Season 2', 'https://myanimelist.net/images/anime/1170/124312l.jpg', '8.0', 34, 262, 'TV', 24, 'Completed', 'Winter 2023', '[\"Action\", \"Adventure\", \"Drama\"]', 0, '2026-03-06 19:00:17', '2026-03-06 19:00:17', '8.8', 'After his father\'s death and the destruction of his village at the hands of English raiders, Einar wishes for a peaceful life with his family on their newly rebuilt farms. However, fate has other plans: his village is invaded once again. Einar watches helplessly as the marauding Danes burn his lands and slaughter his family. The invaders capture Einar and take him back to Denmark as a slave. \r\n\r\nEinar clings to his mother\'s final words to survive. He is purchased by Ketil, a kind slave owner and landlord who promises that Einar can regain his freedom in return for working in the fields. Soon, Einar encounters his new partner in farm cultivation—Thorfinn, a dejected and melancholic slave. As Einar and Thorfinn work together toward their freedom, they are haunted by both sins of the past and the ploys of the present. Yet they carry on, grasping for a glimmer of hope, redemption, and peace in a world that is nothing but unjust and unforgiving.\r\n\r\n[Written by MAL Rewrite]', 49387, 24, 0, NULL, 'Vinland Saga', 0),
(92, 'Bungou Stray Dogs', 'https://myanimelist.net/images/anime/3/79409l.jpg', '8.0', 1110, 90, 'TV', 12, 'Completed', 'Spring 2016', '[\"Action\", \"Mystery\"]', 0, '2026-03-06 19:01:57', '2026-03-06 19:01:57', '7.8', 'For weeks, Atsushi Nakajima\'s orphanage has been plagued by a mystical tiger that only he seems to be unaware of. Suspected to be behind the strange incidents, the 18-year-old is abruptly kicked out of the orphanage and left hungry, homeless, and wandering through the city.\r\n\r\nWhile starving on a riverbank, Atsushi saves a rather eccentric man named Osamu Dazai from drowning. Whimsical suicide enthusiast and supernatural detective, Dazai has been investigating the same tiger that has been terrorizing the boy. Together with Dazai\'s partner Doppo Kunikida, they solve the mystery, but its resolution leaves Atsushi in a tight spot. As various odd events take place, Atsushi is coerced into joining their firm of supernatural investigators, taking on unusual cases the police cannot handle, alongside his numerous enigmatic co-workers.\r\n\r\n[Written by MAL Rewrite]', 31478, 12, 0, NULL, 'Bungou Stray Dogs', 0),
(93, 'Bungou Stray Dogs 2nd Season', 'https://myanimelist.net/images/anime/1572/133096l.jpg', '7.8', 489, 209, 'TV', 12, 'Completed', 'Fall 2016', '[\"Action\", \"Mystery\"]', 0, '2026-03-06 19:02:22', '2026-03-06 19:02:22', '8.2', 'Despite their differences in position, three men—the youngest senior executive of the Port Mafia, Osamu Dazai; the lowest ranking member, Sakunosuke Oda; and the intelligence agent, Ango Sakaguchi—gather at the Lupin Bar at the end of the day to relax and take delight in the company of friends.\r\n\r\nHowever, one night, Ango disappears. A photograph taken at the bar is all that is left of the three together.\r\n\r\nFast forward to the present, and Dazai is now a member of the Armed Detective Agency. The Guild, an American gifted organization, has entered the fray and is intent on taking the Agency\'s work permit. They must now divide their attention between the two groups, the Guild and the Port Mafia, who oppose their very existence.   \r\n\r\n[Written by MAL Rewrite]', 32867, 12, 0, NULL, 'Bungou Stray Dogs', 0),
(95, 'Charlotte', 'https://myanimelist.net/images/anime/1826/147276l.jpg', NULL, 1217, 68, 'TV', 13, 'Plan to watch', 'Summer 2015', '[\"Drama\"]', 0, '2026-03-06 19:04:00', '2026-03-11 16:59:53', '7.8', 'If not for his ability to take over people\'s mind and body, Yuu Otosaka would be an ordinary high school student. Though it only lasts for five seconds at a time, Yuu\'s mysterious power allowed him to cheat his way to the top of his class and  enter a prestigious high school, where he continues his dishonest acts.\r\n\r\nHis shenanigans are eventually stopped by Nao Tomori—the headstrong student council president from Hoshinoumi Academy—who sees through his deceit. Through coercion, Nao convinces Yuu to transfer to Hoshinoumi and join the student council. Hoshinoumi Academy is secretly an institution created for adolescents who possess supernatural abilities—with the student council serving as a means of locating those who abuse their powers.\r\n\r\nWith Yuu begrudgingly assisting in council affairs, the group sets out to find and protect new ability users from harm. However, as they further investigate the abilities, their findings entangle them in far more complicated matters than they could ever imagine.\r\n\r\n[Written by MAL Rewrite]', 28999, 0, 0, NULL, 'Charlotte', 16),
(96, 'Shinseiki Evangelion', 'https://myanimelist.net/images/anime/1314/108941l.jpg', NULL, 247, 45, 'TV', 26, 'Plan to watch', 'Fall 1995', '[\"Avant Garde\", \"Award Winning\", \"Drama\", \"Sci-Fi\", \"Suspense\"]', 0, '2026-03-06 19:04:38', '2026-03-11 16:59:53', '8.4', 'Fifteen years after a cataclysmic event known as the Second Impact, the world faces a new threat: monstrous celestial beings called Angels invade Tokyo-3 one by one. Mankind is unable to defend themselves against the Angels despite utilizing their most advanced munitions and military tactics. The only hope for human salvation rests in the hands of NERV, a mysterious organization led by the cold Gendou Ikari. NERV operates giant humanoid robots dubbed \"Evangelions\" to combat the Angels with state-of-the-art advanced weaponry and protective barriers known as Absolute Terror Fields.\r\n\r\nYears after being abandoned by his father, Shinji Ikari, Gendou\'s 14-year-old son, returns to Tokyo-3. Shinji undergoes a perpetual internal battle against the deeply buried trauma caused by the loss of his mother and the emotional neglect he suffered at the hands of his father. Terrified to open himself up to another, Shinji\'s life is forever changed upon meeting 29-year-old Misato Katsuragi, a high-ranking NERV officer who shows him a free-spirited maternal kindness he has never experienced.\r\n\r\nA devastating Angel attack forces Shinji into action as Gendou reveals his true motive for inviting his son back to Tokyo-3: Shinji is the only child capable of efficiently piloting Evangelion Unit-01, a new robot that synchronizes with his biometrics. Despite the brutal psychological trauma brought about by piloting an Evangelion, Shinji defends Tokyo-3 against the angelic threat, oblivious to his father\'s dark machinations.\r\n\r\n[Written by MAL Rewrite]', 30, 0, 0, NULL, 'Shinseiki Evangelion', 15),
(97, 'Noragami', 'https://myanimelist.net/images/anime/1886/128266l.jpg', NULL, 807, 27, 'TV', 12, 'Plan to watch', 'Winter 2014', '[\"Action\", \"Supernatural\"]', 0, '2026-03-06 19:06:09', '2026-03-11 16:59:53', '7.9', 'In times of need, if you look in the right place, you just may see a strange telephone number scrawled in red. If you call this number, you will hear a young man introduce himself as the Yato God.\r\n\r\nYato is a minor deity and a self-proclaimed \"Delivery God,\" who dreams of having millions of worshippers. Without a single shrine dedicated to his name, however, his goals are far from being realized. He spends his days doing odd jobs for five yen apiece, until his weapon partner becomes fed up with her useless master and deserts him.\r\n\r\nJust as things seem to be looking grim for the god, his fortune changes when a middle school girl, Hiyori Iki, supposedly saves Yato from a car accident, taking the hit for him. Remarkably, she survives, but the event has caused her soul to become loose and hence able to leave her body. Hiyori demands that Yato return her to normal, but upon learning that he needs a new partner to do so, reluctantly agrees to help him find one. And with Hiyori\'s help, Yato\'s luck may finally be turning around.\r\n\r\n[Written by MAL Rewrite]', 20507, 0, 0, NULL, 'Noragami', 14),
(98, 'Fukumenkei Noise', 'https://myanimelist.net/images/anime/11/85350l.jpg', NULL, 4878, 1915, 'TV', 12, 'Plan to watch', 'Spring 2017', '[\"Drama\", \"Romance\"]', 0, '2026-03-06 19:07:14', '2026-03-11 16:59:53', '7.0', 'Every day, a young girl wearing a mask stands by the beach and sings a nostalgic melody. After experiencing two sudden heart-wrenching partings when she was only a child, Nino Arisugawa has been singing her songs to the ocean, bound by a promise made with her two childhood friends—her first love, Momo Sakaki, and a boy who composed music, Kanade \"Yuzu\" Yuzuriha. Having never met each other, the boys both individually promised that if Nino was ever separated from them, her voice would be the beacon to reunite them once again.\r\n\r\nAfter six long years, destiny has finally placed Nino, Momo, and Yuzu in the same high school. However, the passage of time has changed many things in their lives—while Nino relentlessly attempts to fulfill her childhood promise with the boys, Yuzu\'s feelings for her from the past resurface, and Momo goes to great lengths to prevent a reunion with Nino. Through music, will they be able to mend their friendship and overcome all the feelings involved in this complicated love triangle?\r\n\r\n[Written by MAL Rewrite]', 33203, 0, 0, NULL, 'Fukumenkei Noise', 13),
(99, 'Great Teacher Onizuka', 'https://myanimelist.net/images/anime/13/11460l.jpg', NULL, 74, 221, 'TV', 43, 'Plan to watch', 'Summer 1999', '[\"Comedy\"]', 0, '2026-03-06 19:07:47', '2026-03-11 16:59:53', '8.7', 'Twenty-two-year-old Eikichi Onizuka—ex-biker gang leader, conqueror of Shonan, and virgin—has a dream: to become the greatest high school teacher in all of Japan. This isn\'t because of a passion for teaching, but because he wants a loving teenage wife when he\'s old and gray. Still, for a perverted, greedy, and lazy delinquent, there is more to Onizuka than meets the eye. So when he lands a job as the homeroom teacher of the Class 3-4 at the prestigious Holy Forest Academy—despite suplexing the Vice Principal—all of his talents are put to the test, as this class is particularly infamous.\r\n\r\nDue to their utter contempt for all teachers, the class\' students use psychological warfare to mentally break any new homeroom teacher they get, forcing them to quit and leave school. However, Onizuka isn\'t your average teacher, and he\'s ready for any challenge in his way.\r\n\r\nBullying, suicide, and sexual harassment are just a few of the issues his students face daily. By tackling the roots of their problems, Onizuka supports them with his unpredictable and unconventional methods—even if it means jumping off a building to save a suicidal child. Thanks to his eccentric charm and fun-loving nature, Class 3-4 slowly learns just how enjoyable school can be when you\'re the pupils of the Great Teacher Onizuka.\r\n\r\n[Written by MAL Rewrite]', 245, 0, 0, NULL, 'Great Teacher Onizuka', 12),
(106, 'Hunter x Hunter (2011)', 'https://myanimelist.net/images/anime/1337/99013l.jpg', NULL, 10, 14, 'TV', 148, 'Plan to watch', 'Fall 2011', '[\"Action\", \"Adventure\", \"Fantasy\"]', 0, '2026-03-06 19:16:11', '2026-03-11 16:59:53', '9.0', 'Hunters devote themselves to accomplishing hazardous tasks, all from traversing the world\'s uncharted territories to locating rare items and monsters. Before becoming a Hunter, one must pass the Hunter Examination—a high-risk selection process in which most applicants end up handicapped or worse, deceased.\r\n\r\nAthletic participants that challenge the notorious exam carry their own reason for participating. What drives 12-year-old Gon Freecss is finding Ging, his father and a Hunter himself. Believing that he will meet his father by becoming a Hunter, Gon takes the first step to walk the same path.\r\n\r\nDuring the Hunter Examination, Gon befriends the medical student Leorio Paladiknight, the vindictive Kurapika, and ex-assassin Killua Zoldyck. While their motives vastly differ from each other, they band together for a common goal and begin to venture into a perilous world.\r\n\r\n[Written by MAL Rewrite]', 11061, 0, 0, NULL, 'Hunter x Hunter', 11),
(108, 'JoJo no Kimyou na Bouken (TV)', 'https://myanimelist.net/images/anime/3/40409l.jpg', NULL, 288, 59, 'TV', 26, 'Plan to watch', 'Fall 2012', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:18:25', '2026-03-11 16:59:53', '8.3', 'In 1868, Dario Brando saves the life of an English nobleman, George Joestar. By taking in Dario\'s son Dio when the boy becomes fatherless, George hopes to repay the debt he owes to his savior. However Dio, unsatisfied with his station in life, aspires to seize the Joestar house for his own. Wielding an Aztec stone mask with supernatural properties, he sets out to destroy George and his son, Jonathan \"JoJo\" Joestar, and triggers a chain of events that will continue to echo through the years to come.\r\n\r\nHalf a century later, in New York City, Jonathan\'s grandson Joseph Joestar discovers the legacy his grandfather left for him. When an archeological dig unearths the truth behind the stone mask, he realizes that he is the only one who can defeat the Pillar Men, mystical beings of immeasurable power who inadvertently began everything.\r\n\r\nAdapted from the first two arcs of Hirohiko Araki\'s outlandish manga series, JoJo no Kimyou na Bouken follows the many thrilling expeditions of JoJo and his descendants. Whether it\'s facing off with the evil Dio, or combatting the sinister Pillar Men, there\'s always plenty of bizarre adventures in store.\r\n\r\n[Written by MAL Rewrite]', 14719, 0, 0, NULL, 'JoJo', 10),
(109, 'JoJo no Kimyou na Bouken Part 3: Stardust Crusaders', 'https://myanimelist.net/images/anime/11/55267l.jpg', NULL, 477, 85, 'TV', 24, 'Plan to watch', 'Spring 2014', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:19:10', '2026-03-11 16:59:53', '8.1', 'Years after an ancient evil was salvaged from the depths of the sea, Joutarou Kuujou sits peacefully within a Japanese jail cell. He\'s committed no crime yet demands he not be released, believing he\'s been possessed by an evil spirit capable of harming those around him. Concerned for her son, Holly Kuujou asks her father, Joseph Joestar, to convince Joutarou to leave the prison. Joseph informs his grandson that the \"evil spirit\" is in fact something called a \"Stand,\" the physical manifestation of one\'s fighting spirit which can assume a variety of deadly forms. After a fiery brawl with Joseph\'s friend Mohammed Avdol, Joutarou is forced out of his cell and begins learning how to control the power of his Stand.\r\n\r\nHowever, when a Stand awakens within Holly and threatens to consume her in 50 days, Joutarou, his grandfather, and their allies must seek out and destroy the immortal vampire responsible for her condition. They must travel halfway across the world to Cairo, Egypt and along the way, do battle with ferocious Stand users set on thwarting them. If Joutarou and his allies fail in their mission, humanity is destined for a grim fate.\r\n\r\n[Written by MAL Rewrite]', 20899, 0, 0, NULL, 'JoJo', 9),
(110, 'JoJo no Kimyou na Bouken Part 3: Stardust Crusaders 2nd Season', 'https://myanimelist.net/images/anime/11/75045l.jpg', NULL, 126, 116, 'TV', 24, 'Plan to watch', 'Winter 2015', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:19:39', '2026-03-11 16:59:53', '8.5', 'Joutarou Kuujou and his allies have finally made it to Egypt, where the immortal Dio awaits. Upon their arrival, the group gains a new comrade: Iggy, a mutt who wields the Stand \"The Fool.\" However, it won\'t be all smooth sailing for them since standing in their way is a new group of Stand users who serve Dio, each with a Stand representative of an ancient Egyptian god. As their ultimate battle draws near, it is a race against time to break Joutarou\'s mother from her curse and end Dio\'s reign of terror over the Joestar family once and for all.\r\n\r\n[Written by MAL Rewrite]', 26055, 0, 0, NULL, 'JoJo', 8),
(111, 'JoJo no Kimyou na Bouken Part 4: Diamond wa Kudakenai', 'https://myanimelist.net/images/anime/3/79156l.jpg', '10.0', 70, 75, 'TV', 39, 'Completed', 'Spring 2016', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:22:20', '2026-03-06 19:22:20', '8.6', 'The year is 1999. Morioh, a normally quiet and peaceful town, has recently become a hotbed of strange activity. Joutarou Kuujou, now a marine biologist, heads to the mysterious town to meet Jousuke Higashikata. While the two may seem like strangers at first, Jousuke is actually the illegitimate child of Joutarou\'s grandfather, Joseph Joestar. When they meet, Joutarou realizes that he may have more in common with Jousuke than just a blood relation.\r\n\r\nAlong with the mild-mannered Kouichi Hirose and the boisterous Okuyasu Nijimura, the group dedicates themselves to investigating recent disappearances and other suspicious occurrences within Morioh. Aided by the power of Stands, the four men will encounter danger at every street corner, as it is up to them to unravel the town\'s secrets, before another occurs.\r\n\r\n[Written by MAL Rewrite]', 31933, 39, 0, NULL, 'JoJo', 0),
(112, 'JoJo no Kimyou na Bouken Part 5: Ougon no Kaze', 'https://myanimelist.net/images/anime/1572/95010l.jpg', '9.0', 78, 67, 'TV', 39, 'Completed', 'Fall 2018', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:22:56', '2026-03-06 19:22:56', '8.6', 'In the coastal city of Naples, corruption is teeming—the police brazenly conspire with outlaws, drugs run rampant around the youth, and the mafia governs the streets with an iron fist. However, various fateful encounters will soon occur.\r\n\r\nEnter Giorno Giovanna, a 15-year-old boy with an eccentric connection to the Joestar family, who makes a living out of part-time jobs and pickpocketing. Furthermore, he is gifted with the unexplained Stand ability \"Gold Experience,\" which gives him the power to instantiate and manipulate life. Desiring to alter the depleting society around him, he has set to fulfill his dream of becoming a \"Gang-Star.\" Ultimately, he hopes to overthrow the capo of the Passione mafia syndicate and conquer the organization from the inside out.\r\n\r\nAs Giorno is backed by Bruno Bucciarati, a member of Passione with his own sense of justice, they descend into the syndicate\'s intertwined and ruthless turf—all while steering past the other oblivious gangs. By joining Bucciarati\'s team of marginalized soldiers, whose own aspirations stand beside his, Giorno makes a move against the hidden boss commanding them.\r\n\r\n[Written by MAL Rewrite]', 37991, 39, 0, NULL, 'JoJo', 0),
(113, 'JoJo no Kimyou na Bouken Part 6: Stone Ocean', 'https://myanimelist.net/images/anime/1896/119932l.jpg', '7.0', 600, 154, 'ONA', 12, 'Completed', 'Fall 2021', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:24:26', '2026-03-06 19:24:26', '8.0', 'In Florida, 2011, Jolyne Kuujou sits in a jail cell like her father Joutarou once did; yet this situation is not of her own choice. Framed for a crime she didn’t commit and manipulated into serving a longer sentence, Jolyne is ready to resign to a dire fate as a prisoner of Green Dolphin Street Jail. Though all hope seems lost, a gift from Joutarou ends up awakening her latent abilities, manifesting into her Stand, Stone Free. Now armed with the power to change her fate, Jolyne sets out to find an escape from the stone ocean that holds her.\r\n\r\nHowever, she soon discovers that her incarceration is merely a small part of a grand plot: one that not only takes aim at her family, but has additional far-reaching consequences. What\'s more, the mastermind is lurking within the very same prison, and is under the protection of a lineup of menacing Stand users. Finding unlikely allies to help her cause, Jolyne sets her course to stop their plot, clear her name, and take back her life.\r\n\r\n[Written by MAL Rewrite]', 48661, 12, 0, NULL, 'JoJo', 0),
(114, 'JoJo no Kimyou na Bouken Part 6: Stone Ocean Part 2', 'https://myanimelist.net/images/anime/1183/126938l.jpg', '9.0', 484, 532, 'ONA', 12, 'Completed', 'Fall 2022', '[\"Action\", \"Adventure\", \"Supernatural\"]', 0, '2026-03-06 19:25:34', '2026-03-06 19:25:34', '8.1', 'Jolyne Kuujou’s pursuit of the cunning priest Enrico Pucci continues across the Florida prison Green Dolphin Street. Jolyne’s father, Joutarou, sits in a coma-like state as Pucci greedily consumes the man’s Stand and memories. To save her father, Jolyne must claim back the stolen components and put an end to Pucci’s menacing presence for good. \r\n\r\nMeanwhile, Pucci inches ever closer to enacting the final wishes of Jolyne’s mortal enemy—the vampire Dio Brando. Jolyne has assembled a ragtag group of Stand users within the prison to confront the priest head-on. As the enemy moves in on Jolyne, the battle lines are firmly drawn. Jolyne’s next steps dictate either triumph for her father or a crushing defeat that jeopardizes everyone. \r\n\r\n[Written by MAL Rewrite]', 51473, 12, 0, NULL, 'JoJo', 0),
(115, 'JoJo no Kimyou na Bouken Part 6: Stone Ocean Part 3', 'https://myanimelist.net/images/anime/1666/133038l.jpg', '9.0', 79, 735, 'ONA', 14, 'Completed', 'Winter 2023', '[\"Action\", \"Adventure\", \"Drama\", \"Supernatural\"]', 0, '2026-03-06 19:26:01', '2026-03-06 19:26:01', '8.6', 'The end is near. After escaping Green Dolphin Street Prison, prison priest Enrico Pucci begins to enact the final stages of his diabolical master plan: the creation of a universe in which everyone knows their fate. Despite taking numerous heavy losses for simply coming this far, Jolyne Kuujou and her comrades keep Pucci in their sights, closely following him to the shores of Cape Canaveral.\r\n\r\nThe situation swiftly spirals from bad to worse as Pucci further unleashes the unbridled power dwelling within himself. Cornered with practically no chance of victory, it begins to seek like luck itself serves Pucci. The heroes must do whatever is necessary to foil his scheme; otherwise, their demise will symbolize the end of the universe as they know it.\r\n\r\nAs one century-spanning saga reaches a startling conclusion, JoJo no Kimyou na Bouken Part 6: Stone Ocean Part 3 sees its battered combatants putting everything they have on the line, hoping their determination will pave the way toward a better tomorrow.\r\n\r\n[Written by MAL Rewrite]', 51648, 14, 0, NULL, 'JoJo', 0),
(116, 'Fullmetal Alchemist: Brotherhood', 'https://myanimelist.net/images/anime/1208/94745l.jpg', '9.0', 2, 3, 'TV', 64, 'Completed', 'Spring 2009', '[\"Action\", \"Adventure\", \"Drama\", \"Fantasy\"]', 0, '2026-03-06 19:27:07', '2026-03-06 19:27:07', '9.1', 'After a horrific alchemy experiment goes wrong in the Elric household, brothers Edward and Alphonse are left in a catastrophic new reality. Ignoring the alchemical principle banning human transmutation, the boys attempted to bring their recently deceased mother back to life. Instead, they suffered brutal personal loss: Alphonse\'s body disintegrated while Edward lost a leg and then sacrificed an arm to keep Alphonse\'s soul in the physical realm by binding it to a hulking suit of armor.\r\n\r\nThe brothers are rescued by their neighbor Pinako Rockbell and her granddaughter Winry. Known as a bio-mechanical engineering prodigy, Winry creates prosthetic limbs for Edward by utilizing \"automail,\" a tough, versatile metal used in robots and combat armor. After years of training, the Elric brothers set off on a quest to restore their bodies by locating the Philosopher\'s Stone—a powerful gem that allows an alchemist to defy the traditional laws of Equivalent Exchange.\r\n\r\nAs Edward becomes an infamous alchemist and earns the nickname \"Fullmetal,\" the boys\' journey embroils them in a growing conspiracy that threatens the fate of the world.\r\n\r\n[Written by MAL Rewrite]', 5114, 64, 0, NULL, 'Fullmetal Alchemist', 0);
